  ('fire-eq-eng-moex-00100', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關第五種滅火設備除滅火器外之其他設備，其規定水槽每W公升為X滅火效能值；乾燥砂每50公升 為Y滅火效能值；膨脹蛭石每Z公升為一滅火效能值，請問上述W、X、Y、Z分別為何？', '["W=8；X=0.5；Y=1；Z=80", "W=80；X=0.5；Y=1.5；Z=160", "W=80；X=1.5；Y=0.5；Z=160", "W=160；X=1.5；Y=0.5；Z=80"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
